var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다시 정식으로 인사드리겠습니다.","JPN":"改めてご挨拶申し上げます。","ENG":"Please let us introduce ourselves properly again.","TWN":"這裡再次正式地向你們問好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저는 경찰청 직속 특수능력 범죄 대응 전담반인 제 4 특별기동수사대 임시직 경정,","JPN":"私は警察庁直属の特殊能力犯罪専担班、\\n第4特別機動捜査隊の臨時職員で警視の、","ENG":"I’ve been temporarily assigned to Police SWAT 4, the Counter-superpowered crimes team directly subordinate to police headquarters.","TWN":"我是警察廳直屬特殊能力犯罪專案組、第四特遣機動隊臨時警正。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이유미입니다.","JPN":"カスカベ・ユミです。","ENG":"I’m Major Lee Yumi.","TWN":"我叫李悠美。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저는 강소영이라고 해요.","JPN":"私はマエカワ・ナツミと申します。","ENG":"And I’m Kang Soyoung.","TWN":"我是姜素英。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우와, 이게 프로 카운터 분들이 타고 다니는 함선인가요?","JPN":"うわ～！　これがプロのカウンターが乗る艦船ですか？","ENG":"Wow, so is this the ride for professional Counters like you?","TWN":"哇，這是專業制裁者乘坐的艦船嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"엄청 크다~!","JPN":"ものすごくおっきい～！","ENG":"It’s huge!","TWN":"太大了吧～！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위! 제발 촐싹거리지 좀 마!","JPN":"マエカワ警部補！　お願いだから落ち着いて！","ENG":"Lieutenant Kang! Please behave yourself!","TWN":"姜素英警衛，不要這麼放肆！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시민의 안전을 책임지는 경찰답게 진중한 모습을 보이라고!","JPN":"市民の安全を守る警察らしく、落ち着いた姿を見せないと！","ENG":"Try to present yourself with the gravity fitting of a police officer who's vowed to protect and serve!","TWN":"請妳有點人民保母的樣子，莊重點！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 경정님이야말로 너무 딱딱하시다니까?","JPN":"ははは、警視様のほうこそ堅すぎますよ？","ENG":"Haha, don’t be the fun police too, Major.","TWN":"哈哈，警正大人這個樣子不會太沉悶嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"시민들에게는 친절하게 다가가야죠.","JPN":"市民にはフレンドリーに接しないと。","ENG":"We ought to be more approachable for the citizens.","TWN":"對待市民要親切一點啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그건 그렇지만......","JPN":"そ、それはそうだけど……","ENG":"B-but...","TWN":"就、就算是這樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇게 스트레스를 받으니까 경정님도 흰머리만 늘잖아요.","JPN":"そうやってストレスを溜めるから、白髪が増えるばかりじゃないですか。","ENG":"You keep getting all that gray hair because you're always so tightly wound up.","TWN":"警正大人妳壓力那麼大，都要長白頭髮了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아, 아니! 무슨 소릴 하는 거야?","JPN":"ええっ、何言ってるの！","ENG":"W-what?! What are you talking about?","TWN":"啊，討厭！妳說什麼！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"나, 흰머리 같은 거 없다고!","JPN":"私、白髪なんてないですけど！","ENG":"I don't have gray hair!","TWN":"我才沒有白頭髮！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"또 스트레스 받는다. 릴렉스, 릴렉스.","JPN":"またストレス溜めてる。リラックス、リラックス～！","ENG":"Oh, there you go stressing out again. Take a chill pill.","TWN":"妳看，妳又有壓力了。放輕鬆，放輕鬆。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......이 여자가 정말!!","JPN":"……いい加減にしなさいよ！！","ENG":"Why, you little!","TWN":"……這個女人真是的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"만날 사람들이라는 게 경찰이었어?","JPN":"助っ人って、警察だったの？","ENG":"So the assets... are the police?","TWN":"我們要見的人就是警察嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일반 경찰이 침식체나 리플레이서를 상대하긴 어려울 텐데. 범죄 수사도 아니고......","JPN":"普通の警察が侵食体やリプレイサーを相手するのは難しいと思うけど……\\n犯罪捜査じゃあるまいし……","ENG":"No offense, but I’m not sure if ordinary cops have what it takes to fight C.O.'s or the Replacers. This isn’t a typical crime scene...","TWN":"一般來說，警察很難對付侵蝕體和克隆集團的。畢竟這不是一般的犯罪偵查……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"실례로군요! 저희는 평범한 경찰조직이 아닙니다.","JPN":"失敬な！　私たちは普通の警察ではありません。","ENG":"Offense taken! We’re no ordinary police.","TWN":"抱歉，我們不是普通的警察。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우리 제 4 특별기동수사대는 특수능력자 범죄,","JPN":"第4特別機動捜査隊は特殊能力者による犯罪、","ENG":"Police SWAT 4 handles crimes committed by superpowered individuals.","TWN":"第四特遣機動隊是為了打擊能力者犯罪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"특히 카운터 능력자나 이터니움 관련 범죄에 대응하기 위해 만들어진 전문부서입니다!","JPN":"カウンター能力者やエタニウム関連犯罪に対応するために作られた専門部署なんです！","ENG":"Specifically, the organization was established to tackle crimes related to Counters or Eternium!","TWN":"尤其是制裁者能力者犯罪，以及和永恆之金有關的犯罪而設立的專門部門。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그런 거야? 미안해. 잘 몰라서.......","JPN":"そ、そうなの？　ごめんね。あまり詳しくなくて……","ENG":"I-is that right? Sorry. I didn’t know...","TWN":"是，是這樣嗎？抱歉，我之前不太清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 괜찮아요, 괜찮아. ","JPN":"ははは、気にしない、気にしない～。","ENG":"Haha... It’s fine. No worries. ","TWN":"哈哈，沒關係，沒關係。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"사실 명목상만 그렇지, 딱히 내세울 만한 성과도 지원도 없는 전형적인 전시행정용 부서거든요.","JPN":"実際は名目だけで、これといった成果も支援もない典型的なお飾りの部署なんですから。","ENG":"That’s what it says on paper. In reality, we're basically for just show, with virtually no track record. We hardly get any real support from the force either.","TWN":"其實也只有名義上是那樣，也沒有什麼值得驕傲的業績或者支援，典型的展示用行政部門啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"가, 강소영 경위! 대체 무슨 소릴 하는 거야?!","JPN":"マ、マエカワ警部補！　いったい何を言ってるの！？","ENG":"L-lieutenant! That’s highly inappropriate!","TWN":"姜素英警衛，妳到底在說什麼啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 사실이잖아요? ","JPN":"でも、事実じゃないですか。","ENG":"But it’s true, isn’t it? ","TWN":"但是我說的不是事實嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님이 오기 전까지만 해도 1년이 넘도록 상근직은 나 혼자뿐이었는걸......","JPN":"警視様が来る前は、勤続1年が過ぎても常勤は私一人だけでしたよ。","ENG":"I was the only permanent member on the team for over a year until you showed up.","TWN":"警正大人您來之前，有超過一年時間裡只有我一個全勤職員……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"다른 팀원이라고 해 봐야 교통계의 박지훈 아저씨가 정년 퇴직 전에 두 달 정도 있었던 거랑......","JPN":"他の班員といっても、交通係の馬場さんが定年退職前に2ヶ月ほどいたのと……","ENG":"The only other time I had another teammate was when Sergeant Park from traffic control stuck around for two months before his retirement...","TWN":"要說其他警員的話，管交通的朴智勳大叔在退休前，在我們部門待了兩個月……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"연말 보고서 정리 때문에 관리부서의 보나 선배가 임시직으로 잠시 근무한 정도?","JPN":"年末報告書の整理のために、管理部署のホナミ先輩が\\n臨時職員としてしばらく勤めていた程度でしょうか。","ENG":"Oh, I guess Bona from admin also worked in the office temporarily to help me out with the annual report.","TWN":"還有為了整理年末報告，從管理部門臨時調來的寶娜姐姐？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"겨, 경찰의 위신이 무너지는 소리는 제발 그만두세요! 강소영 경위!!","JPN":"け、警察の威信が失墜するような話はお願いだからやめなさい！　マエカワ警部補！！","ENG":"P-please stop ruining the police's reputation like that! Lieutenant Kang!","TWN":"姜素英警衛！不、不要再說這種有損警察威信的話了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 뭐 이 정도로 위신이 무너질 것까지야......","JPN":"ははは、この程度で威信が失墜するなんて……","ENG":"Aw, I think you're just blowing this out of proportion ma’am. Haha.","TWN":"哈哈，這樣就有損警察威信了啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"다들 아는 이야기인데 말이죠.","JPN":"知らない人、いないと思いますけどね。","ENG":"Everyone knows about this already anyway.","TWN":"都是大家知道的事情啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"말이 나와서 말이지, 부서만 달랑 만들어 놓고 일반인에게 카운터 범죄자를 잡으라니.......","JPN":"正直、部署だけ作っておいて一般人にカウンター犯罪者を捕まえろだなんて……","ENG":"I mean, they expect us regular folks to apprehend Counter criminals just because we come from a department with a fancy name?","TWN":"說到這裡，只設立一個部門就讓普通人去抓制裁者犯人……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 말이 되겠어요? 하하.","JPN":"そんなの、あり得ますかね？　あはは。","ENG":"That’s nonsense. Haha.","TWN":"這像話嗎？哈哈哈。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"바로 그런 태도가 문제라고!","JPN":"まさにその態度が問題なのよ！","ENG":"It’s that attitude of yours that’s ruining our reputation!","TWN":"妳這是什麼態度！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일반인? 이쪽은 카운터처럼 보이는데......?","JPN":"一般人？　こっちはカウンターみたいだけど？","ENG":"Regular folks? But she looks like a Counter...","TWN":"普通人？這位看起來好像是制裁者啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 이유미 경정님은 특별 채용으로 아직 4 기동에 배치된 지 얼마 안 됐거든요.","JPN":"あ、カスカベ警視様は\\n特別採用された方で、第4特別機動捜査隊に配属されたばかりなんです。","ENG":"Oh, Major Lee was only recently assigned to Police SWAT 4 after a special recruitment.","TWN":"啊，李悠美警正是被破格錄用的，分配到第4特別機動隊還沒多久呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇군...... 그런데 경정이라니?","JPN":"そうなんだ……ところで、警視って？","ENG":"I see... But a Major?","TWN":"這樣啊……可是她是警正？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 경찰 조직은 잘 모르지만 그거 꽤 높은 자리 아냐?","JPN":"警察組織については詳しくないけど、結構上の方なんじゃない？","ENG":"I’m not too familiar with police ranks... but isn’t that pretty high up?","TWN":"我雖然不太瞭解警察組織，但警正職務挺高的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내 또래처럼 보이는데...... 말로만 듣던 초 엘리트 같은 건가?","JPN":"私と同年代に見えるけど……噂に聞く、超エリートなのかな？","ENG":"She doesn’t look much older than me... Is she one of those super fast-track elites?","TWN":"看起來和我年齡相仿……就是傳說中的超級精英嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 비슷해요.","JPN":"まあ、似たようなもんですね。","ENG":"Something like that.","TWN":"額，差不多那個意思吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"보통 카운터 능력자가 경찰공무원을 지망하는 경우는 거의 없거든요.","JPN":"カウンター能力者が警察官を志望するケースは、ほとんどないですから。","ENG":"It’s not every day that Counters apply for the police force.","TWN":"一般來說，制裁者能力者中幾乎沒幾個人志向是當警察的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런 박봉에 힘들기만 한 일보다는 훨씬 대우가 좋은 직장들이 널려 있으니까요.","JPN":"こんな安月給で苦労してばかりの仕事よりも、ずっと待遇のいい職場がたくさんありますし。","ENG":"There’s plenty of job opportunities out there with better pay and perks than this crappy job.","TWN":"警察薪資少事情還多，比警察待遇好的工作太多了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런데 이유미 경정님은 본인이 직접 경찰에 지원한 특이 케이스라서요.","JPN":"カスカベ警視様は、自ら警察に志願した特殊なケースなんです。","ENG":"But Major Lee volunteered for the force, making her extra special.","TWN":"但是李悠美警正是個特例，她是自己想當警察的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"상부에서 도망가지 못하도록 떡 하니 재갈을......","JPN":"だからこそ、上層部からは、逃げられないように首輪を……","ENG":"That’s why the top brass tried to keep her by putting her in chains...","TWN":"為了使她不脫離上級的管轄，所以公然地給她戴上了手銬……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아니, 감투를 씌워 놓은 거죠.","JPN":"いや、役職を与えられているんですよね。","ENG":"Uh, I mean, putting her high up in the chain of command.","TWN":"不是，是給她戴了烏紗帽。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"물론 아직 미성년자라 임시직이긴 하지만요.","JPN":"もちろん未成年なので臨時職ではありますけどね。","ENG":"Of course, she's still a temp because she's a minor.","TWN":"雖然現在還未成年，只是臨時職務。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......아직도 그 소리야?","JPN":"……またその話？","ENG":"You still going on about that?","TWN":"……妳又在說這個了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난 대우나 직급 같은 건 관심 없다니까?","JPN":"私は待遇や役職なんかに興味ないんだから。","ENG":"I told you, I don't care about perks or ranks!","TWN":"我才不關心待遇和職位這種東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 그렇게 말해도 상부에서는 걱정할 만하죠.","JPN":"警視様はそうだとしても、上層部は心配になりますよ。","ENG":"You may say so, but the leadership has every reason to be concerned.","TWN":"警正大人妳雖然這麼說，上級還是很擔心呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대체 얼마만에 들어온 카운터 능력자인데, 이대로 휙~ 떠나 버리기라도 하면 그 책임을 대체 누가 지겠어요?","JPN":"待望のカウンター能力者が入ったのに、さくっと辞められたりしたらその責任は誰がとるんですか？","ENG":"It's been ages since we had a Counter on the force. Nobody would want to be responsible for someone like you leaving us so soon.","TWN":"好不容易才來一個制裁者能力者，要是突然走了誰來負這個責任啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다시 말하지만 난 직급 같은 건 관심 없고, 떠날 생각도 없어.","JPN":"改めて言うけど、私は役職なんか興味ないし、辞めるつもりもない。","ENG":"Like I said, I’m not interested in titles, or thinking about leaving.","TWN":"我再說一遍，我不關心什麼待遇和職位。我也沒有要離職。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가 신경 쓰는 건 오직 카운터 범죄자 놈들을 근절하는 일뿐이야.","JPN":"私が気にしているのは、カウンター犯罪者のやつらを根絶することだけ。","ENG":"The only thing I care about is bringing an end to crimes committed by Counters.","TWN":"我只關心要怎麼杜絕制裁者犯罪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당신 같은 무능력자들에게 맡겨 놨다간 대체 이 도시가 어떻게 될지......","JPN":"あなたのような無能力者たちに任せて\\nおいたら、いったいこの都市はどうなることか……","ENG":"If we leave that to incompetents like you, who knows what will happen to this city?","TWN":"把任務交給妳這樣的無能者，真不知道會把城市搞成什麼樣子……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"생각만 해도 끔찍해.","JPN":"考えただけでもぞっとするわ。","ENG":"The thought of it makes me nauseous.","TWN":"簡直難以想像。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네이, 네이. 알겠습니다요, 경정님.","JPN":"はい、はい。わかりましたよ、警視様。","ENG":"Sure, sure. Whatever you say, Major.","TWN":"是，是。知道了啦，警正大人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그쪽도 사정이 복잡한가 보네.","JPN":"……そっちも色々事情があるんだね。","ENG":"Sounds... complicated.","TWN":"……那邊情況好像也有些複雜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 행정조직이라는 게 다 그렇죠 뭐.","JPN":"はは、まあ行政組織って、だいたいそんなもんでしょう。","ENG":"Haha, there's always red tape in government organizations, am I right?","TWN":"哈哈，行政組織什麼的就是那樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......즐거운 수다시간은 끝났나?","JPN":"楽しいおしゃべりタイムは終わったか？","ENG":"Done chatting?","TWN":"……開心的聊天時間結束了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"괜찮으면 슬슬 의뢰인과 이야기를 했으면 좋겠는데.","JPN":"よければ、そろそろ依頼人と話がしたいのだが。","ENG":"I’d like to speak with the client now, if you don't mind.","TWN":"可以的話，我差不多想要和委託人談話了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 알겠습니다. 그럼 쿠퍼 양과 통신을 연결할게요.","JPN":"あ、わかりました。それではクーパーさんと繋げますね。","ENG":"U-understood. We’ll put you through to Ms. Cooper then.","TWN":"好的，知道了。那我就聯絡庫博小姐囉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};